ype').focus();            //alert('Enter address_type.');            return false;        } else {        }                if (country == '') {            $('#country').focus();            //alert('Enter country.');            return false;        } else {        }                if (state == '') {            $('#state').focus();            //alert('Enter state.');            return false;        } else {        }                if (city == '') {            $('#city').focus();            //alert('Enter city.');            return false;        } else {        }                if (address == '') {            $('#address').focus();            //alert('Enter address.');            return false;        } else {        }                                return $.ajax({            url: "{{ route('updateAddress') }}",            type: 'POST',            data: {                "_token": "{{ csrf_token() }}",                address_id: address_id,                address_type: address_type,                country: country,                state: state,                city: city,                address: address            },            beforeSend: function(res) {                //$('#state').html('<option value="">Loading...</option>');            },            success: function(res) {                //console.log(res);                if(res.status=='success'){                                       $('#subitAddMessage').html('<div id="alertMessage" class="alert alert-success" role="alert">Address updated successfully!</div>');                    window.location.reload();                }else{                    $('#subitAddMessage').html('<div id="alertMessage" class="alert alert-danger" role="alert">Something went wrong!</div>');                  }            }        })    }            function updateProfile() {                var first_name = $('#first_name').val();        var last_name = $('#last_name').val();        var email = $('#email').val();        var mobile = $('#mobile').val();        var dob = $('#dob').val();        var gender = $('#gender').val();                if (first_name == '') {                        $('#first_name').focus();            //alert('Enter first name.');            return false;        } else {        }                /*if (email == '') {            $('#email').focus();            //alert('Enter email.');            return false;        } else {        }*/                if (mobile == '') {            $('#mobile').focus();            //alert('Enter mobile.');            return false;        } else {        }                                return $.ajax({            url: "{{ route('updateProfile') }}",            type: 'POST',            data: {                "_token": "{{ csrf_token() }}",                first_name: first_name,                last_name: last_name,                email: email,                mobile: mobile,                dob: dob,                gender: gender            },            beforeSend: function(res) {                //$('#state').html('<option value="">Loading...</option>');            },            success: function(res) {                //console.log(res);                if(res.status=='success'){                    /*$('#first_name').val('');                    $('#last_name').val('');                    $('#email').val('');                    $('#mobile').val('');                    $('#dob').val('');                    $('#gender').val('');*/                                        $('#subitMessage').html('<div id="alertMessage" class="alert alert-success" role="alert">Profile updated successfully!</div>');                    window.location.reload();                }else{                    $('#subitMessage').html('<div id="alertMessage" class="alert alert-danger" role="alert">Something went wrong!</div>');                  }            }        })    }    </script>  @endsection